mapper.insert:
insert into store_coach_evaluate (evaluateId, scId, userId, 
  headImgUrl, nickname, evLevel, 
  evContent, evaluatImgUrl, evaluatDate
  )
values (#{evaluateId,jdbcType=BIGINT}, #{scId,jdbcType=BIGINT}, #{userId,jdbcType=BIGINT}, 
  #{headImgUrl,jdbcType=VARCHAR}, #{nickname,jdbcType=VARCHAR}, #{evLevel,jdbcType=INTEGER},
  #{evContent,jdbcType=VARCHAR}, #{evaluatImgUrl,jdbcType=VARCHAR}, #{evaluatDate,jdbcType=TIMESTAMP}
  )

mapper.select:
SELECT u.nickname,u.headImgUrl,ce.evLevel,ce.evaluatDate,ce.evContent,ce.evaluatImgUrl
FROM store_coach_evaluate ce
LEFT JOIN user_info u ON u.userId = ce.userId
WHERE ce.scId = #{coachId}
ORDER BY ce.evaluatDate DESC

    limit #{offset}, #{limit}
